import XCTest
@testable import dbv_nfc_games

/// Cross-platform DTO contract tests for iOS.
///
/// Validates that iOS model structs can correctly decode the canonical JSON
/// snapshots generated by the backend. This catches DTO drift between
/// backend and iOS.
final class DtoContractTests: XCTestCase {

