    // These match the canonical snapshots in contract-snapshots/ at the repo root.
    // Embedded as inline strings because Xcode test bundles cannot easily
    // reference files outside the project directory.
    //
    // IMPORTANT: These inline JSON strings MUST be kept in sync with the
    // canonical snapshot files at:
    //   <repo-root>/contract-snapshots/AuthResponse.json
    //   <repo-root>/contract-snapshots/PlayerAuthResponse.json
    //   <repo-root>/contract-snapshots/GameResponse.json
    //   <repo-root>/contract-snapshots/SubmissionResponse.json
    //   <repo-root>/contract-snapshots/BaseProgressResponse.json
    //   <repo-root>/contract-snapshots/LeaderboardEntry.json
    //
    // If the backend regenerates snapshots, update these inline strings to match.
    // The testInlineSnapshotKeysMatchExpectedContractStructure() test below
    // validates the JSON key structure to catch accidental divergence.

