    func testAuthResponse_decodesFromContractSnapshot() throws {
        let dto = try JSONDecoder().decode(OperatorAuthResponse.self, from: authResponseJSON)

        XCTAssertEqual(dto.accessToken, "eyJhbGciOiJIUzI1NiJ9.test-access-token")
        XCTAssertEqual(dto.refreshToken, "eyJhbGciOiJIUzI1NiJ9.test-refresh-token")
        XCTAssertEqual(dto.user.id, UUID(uuidString: "a1b2c3d4-e5f6-7890-abcd-ef1234567890"))
        XCTAssertEqual(dto.user.email, "operator@example.com")
        XCTAssertEqual(dto.user.name, "Test Operator")
        XCTAssertEqual(dto.user.role, "operator")
    }

    func testPlayerAuthResponse_decodesFromContractSnapshot() throws {
        let dto = try JSONDecoder().decode(PlayerAuthResponse.self, from: playerAuthResponseJSON)

        XCTAssertEqual(dto.token, "eyJhbGciOiJIUzI1NiJ9.test-player-token")
