        XCTAssertEqual(dto.player.displayName, "Scout Team Alpha")
        XCTAssertEqual(dto.player.deviceId, "ios-device-abc123")
        XCTAssertEqual(dto.team.id, UUID(uuidString: "c3d4e5f6-a7b8-9012-cdef-123456789012"))
        XCTAssertEqual(dto.team.name, "Eagles")
        XCTAssertEqual(dto.team.color, "#FF5733")
        XCTAssertEqual(dto.game.id, UUID(uuidString: "d4e5f6a7-b8c9-0123-defa-234567890123"))
        XCTAssertEqual(dto.game.name, "Forest Adventure")
        XCTAssertEqual(dto.game.description, "A scouting game in the forest")
