        XCTAssertEqual(dto.startDate, "2025-03-01T08:00:00Z")
        XCTAssertEqual(dto.endDate, "2025-03-01T18:00:00Z")
        XCTAssertEqual(dto.createdBy, UUID(uuidString: "a1b2c3d4-e5f6-7890-abcd-ef1234567890"))
        XCTAssertNotNil(dto.operatorIds)
        XCTAssertEqual(dto.operatorIds?.count, 1)
    }

    func testSubmissionResponse_decodesFromContractSnapshot() throws {
        let dto = try JSONDecoder().decode(SubmissionResponse.self, from: submissionResponseJSON)

        XCTAssertEqual(dto.id, UUID(uuidString: "e5f6a7b8-c9d0-1234-efab-345678901234"))
