        XCTAssertEqual(dto.teamId, UUID(uuidString: "c3d4e5f6-a7b8-9012-cdef-123456789012"))
        XCTAssertEqual(dto.teamName, "Eagles")
        XCTAssertEqual(dto.color, "#FF5733")
        XCTAssertEqual(dto.points, 350)
        XCTAssertEqual(dto.completedChallenges, 5)
    }

    // MARK: - Inline snapshot key structure validation
    //
    // This test validates that the inline JSON snapshots above contain the
    // expected top-level and nested key sets from the canonical contract
    // snapshots. If a snapshot is regenerated with new/renamed fields, this
    // test will fail, signaling the inline strings need updating.

    func testInlineSnapshotKeysMatchExpectedContractStructure() throws {
        // Helper to extract sorted keys from JSON data
        func topLevelKeys(_ data: Data) throws -> [String] {
            let obj = try JSONSerialization.jsonObject(with: data) as! [String: Any]
            return obj.keys.sorted()
        }
        func nestedKeys(_ data: Data, key: String) throws -> [String] {
            let obj = try JSONSerialization.jsonObject(with: data) as! [String: Any]
            guard let nested = obj[key] as? [String: Any] else { return [] }
            return nested.keys.sorted()
        }

        // AuthResponse: top-level keys and nested "user" keys
        let authKeys = try topLevelKeys(authResponseJSON)
        XCTAssertEqual(authKeys, ["accessToken", "refreshToken", "user"])
        let authUserKeys = try nestedKeys(authResponseJSON, key: "user")
        XCTAssertEqual(authUserKeys, ["createdAt", "email", "id", "name", "role"])

        // PlayerAuthResponse: top-level keys and nested keys
        let playerAuthKeys = try topLevelKeys(playerAuthResponseJSON)
        XCTAssertEqual(playerAuthKeys, ["game", "player", "team", "token"])
        let playerKeys = try nestedKeys(playerAuthResponseJSON, key: "player")
        XCTAssertEqual(playerKeys, ["deviceId", "displayName", "id"])

        // GameResponse: top-level keys
        let gameKeys = try topLevelKeys(gameResponseJSON)
        XCTAssertEqual(gameKeys, [
            "broadcastCode", "broadcastEnabled", "createdBy", "description",
            "endDate", "id", "name", "operatorIds", "startDate", "status",
            "tileSource", "uniformAssignment"
        ])

        // SubmissionResponse: top-level keys
        let submissionKeys = try topLevelKeys(submissionResponseJSON)
        XCTAssertEqual(submissionKeys, [
            "answer", "baseId", "challengeId", "completionContent", "feedback",
            "fileUrl", "fileUrls", "id", "points", "reviewedBy", "status",
            "submittedAt", "teamId"
        ])

        // BaseProgressResponse: top-level keys
        let baseProgressKeys = try topLevelKeys(baseProgressResponseJSON)
        XCTAssertEqual(baseProgressKeys, [
            "baseId", "baseName", "challengeId", "checkedInAt", "lat",
            "lng", "nfcLinked", "status", "submissionStatus"
        ])

        // LeaderboardEntry: top-level keys
        let leaderboardKeys = try topLevelKeys(leaderboardEntryJSON)
        XCTAssertEqual(leaderboardKeys, [
            "color", "completedChallenges", "points", "teamId", "teamName"
        ])
    }
}
